/**
 * Custom Worker entrypoint wrapping the OpenNext-generated handler so we can
 * add a `scheduled()` cron handler (wrangler.jsonc `triggers.crons`).
 *
 * The cron drains both queues by invoking the app's own API routes in-process
 * (no public round-trip, no duplicated business logic in the entrypoint).
 *
 * `.open-next/worker.js` is generated by `opennextjs-cloudflare build` — run
 * that before `wrangler deploy` / `wrangler dev` (see package.json scripts).
 */
// @ts-ignore — generated at build time
import handler from "./.open-next/worker.js";

const CRON_ROUTES = ["/api/scoring/drain", "/api/emails/drain"];

export default {
  fetch: handler.fetch,

  async scheduled(controller: ScheduledController, env: CloudflareEnv, ctx: ExecutionContext) {
    const base = env.NEXT_PUBLIC_APP_URL || "https://hr.matviet.com.vn";
    for (const path of CRON_ROUTES) {
      const request = new Request(new URL(path, base), {
        headers: { authorization: `Bearer ${env.CRON_SECRET ?? ""}` },
      });
      try {
        const res = (await handler.fetch(request, env, ctx)) as Response;
        console.log(`[cron ${controller.cron}] ${path} -> ${res.status} ${await res.text()}`);
      } catch (err) {
        console.error(`[cron ${controller.cron}] ${path} failed:`, err);
      }
    }
  },
} satisfies ExportedHandler<CloudflareEnv>;

// Re-export Durable Object classes the OpenNext runtime may reference.
// @ts-ignore — generated at build time
export { DOQueueHandler, DOShardedTagCache, BucketCachePurge } from "./.open-next/worker.js";
